import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for string template blocks inside raw string literals.
 *
 * See https://github.com/pinterest/ktlint/issues/1776
 */
internal class WrappingRuleRawStringTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Issue 1776 - Given a let block inside a raw string literal with a long line then do not report a false positive`() {
        val code =
            """
            class QueryGenerator {
                fun getQueryString(query: QueryRequest): String {
                    val q = ${"\"\"\""}
                        SELECT *
                        FROM table_name_long_enough_so_max_line_length_is_met_and_wrapping_rule_is_violated_and_generates_an_error
                        WHERE 1 = 1
                        ${"$"}{query.gameId?.let { "AND id = ?" } ?: ""}    
                    ${"\"\"\""}
                    return q
                }
            }

            data class QueryRequest(
                val gameId: String?,
            )
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 1776 - Given a multiline let block inside a raw string literal then do not report a violation`() {
        val code =
            """
            class QueryGenerator {
                fun getQueryString(query: QueryRequest): String {
                    val q = ${"\"\"\""}
                        SELECT *
                        FROM table
                        WHERE 1 = 1
                        ${"$"}{query.gameId?.let {
                            "AND id = ?"
                        } ?: ""}    
                    ${"\"\"\""}
                    return q
                }
            }

            data class QueryRequest(
                val gameId: String?,
            )
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 1776 - Given a simple block inside a raw string literal then do not report a violation`() {
        val code =
            """
            val foo = ${"\"\"\""}
                ${"$"}{ bar { "baz" } }
            ${"\"\"\""}
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 1776 - Given a let block inside a raw string literal on a single line then do not report a violation`() {
        val code =
            """
            val foo = ${"\"\"\""}${"$"}{bar?.let { "baz" } ?: ""}${"\"\"\""}
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 1776 - Given a run block inside a raw string literal then do not report a violation`() {
        val code =
            """
            val foo = ${"\"\"\""}
                Some text ${"$"}{someValue.run { this.toString() }} more text
            ${"\"\"\""}
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

